// SocialLoginManager.kt
package com.example.sociallogin

import android.app.Activity
import android.content.Context
import android.content.Intent
import android.os.Bundle
import android.util.Log
import androidx.activity.result.ActivityResultLauncher
import com.facebook.CallbackManager
import com.facebook.FacebookCallback
import com.facebook.FacebookException
import com.facebook.login.LoginManager
import com.facebook.login.LoginResult
import com.google.android.gms.auth.api.signin.GoogleSignIn
import com.google.android.gms.auth.api.signin.GoogleSignInAccount
import com.google.android.gms.auth.api.signin.GoogleSignInClient
import com.google.android.gms.auth.api.signin.GoogleSignInOptions
import com.google.android.gms.common.api.ApiException
import com.google.android.gms.tasks.Task

class SocialLoginManager(private val context: Context) {

    private val secretManager = SecretManager(context)
    private var googleSignInClient: GoogleSignInClient? = null
    private var facebookCallbackManager: CallbackManager? = null
    private var loginCallback: SocialLoginCallback? = null

    interface SocialLoginCallback {
        fun onLoginSuccess(provider: LoginProvider, userId: String, accessToken: String, email: String?)
        fun onLoginFailure(provider: LoginProvider, error: String)
        fun onLoginCancelled(provider: LoginProvider)
    }

    enum class LoginProvider {
        FACEBOOK, GOOGLE
    }

    fun initializeGoogle() {
        val clientId = secretManager.getGoogleClientId()
        
        if (clientId.isEmpty()) {
            Log.e(TAG, "Google Client ID not configured")
            return
        }

        val gso = GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_SIGN_IN)
            .requestEmail()
            .requestIdToken(clientId)
            .requestProfile()
            .build()

        googleSignInClient = GoogleSignIn.getClient(context, gso)
    }

    fun initializeFacebook() {
        val appId = secretManager.getFacebookAppId()
        
        if (appId.isEmpty()) {
            Log.e(TAG, "Facebook App ID not configured")
            return
        }

        facebookCallbackManager = CallbackManager.Factory.create()
    }

    fun loginWithGoogle(activity: Activity, callback: SocialLoginCallback) {
        this.loginCallback = callback
        
        if (googleSignInClient == null) {
            initializeGoogle()
        }

        if (googleSignInClient == null) {
            callback.onLoginFailure(LoginProvider.GOOGLE, "Google Sign-In not properly configured")
            return
        }

        val signInIntent = googleSignInClient!!.signInIntent
        activity.startActivityForResult(signInIntent, RC_GOOGLE_SIGN_IN)
    }

    fun loginWithFacebook(activity: Activity, callback: SocialLoginCallback) {
        this.loginCallback = callback
        
        if (facebookCallbackManager == null) {
            initializeFacebook()
        }

        if (facebookCallbackManager == null) {
            callback.onLoginFailure(LoginProvider.FACEBOOK, "Facebook Login not properly configured")
            return
        }

        LoginManager.getInstance().registerCallback(facebookCallbackManager,
            object : FacebookCallback<LoginResult> {
                override fun onSuccess(result: LoginResult) {
                    val userId = result.accessToken.userId
                    val token = result.accessToken.token
                    
                    callback.onLoginSuccess(
                        LoginProvider.FACEBOOK,
                        userId,
                        token,
                        null
                    )
                }

                override fun onCancel() {
                    callback.onLoginCancelled(LoginProvider.FACEBOOK)
                }

                override fun onError(error: FacebookException) {
                    callback.onLoginFailure(LoginProvider.FACEBOOK, error.message ?: "Unknown error")
                }
            })

        LoginManager.getInstance().logInWithReadPermissions(
            activity,
            listOf("email", "public_profile")
        )
    }

    fun handleActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        when (requestCode) {
            RC_GOOGLE_SIGN_IN -> {
                handleGoogleSignInResult(data)
            }
            else -> {
                facebookCallbackManager?.onActivityResult(requestCode, resultCode, data)
            }
        }
    }

    private fun handleGoogleSignInResult(data: Intent?) {
        val task = GoogleSignIn.getSignedInAccountFromIntent(data)
        try {
            val account = task.getResult(ApiException::class.java)
            if (account != null) {
                loginCallback?.onLoginSuccess(
                    LoginProvider.GOOGLE,
                    account.id ?: "",
                    account.idToken ?: "",
                    account.email
                )
            } else {
                loginCallback?.onLoginFailure(LoginProvider.GOOGLE, "Account is null")
            }
        } catch (e: ApiException) {
            if (e.statusCode == 12501) {
                loginCallback?.onLoginCancelled(LoginProvider.GOOGLE)
            } else {
                loginCallback?.onLoginFailure(LoginProvider.GOOGLE, "Sign in failed: ${e.message}")
            }
        }
    }

    fun signOut(provider: LoginProvider) {
        when (provider) {
            LoginProvider.GOOGLE -> {
                googleSignInClient?.signOut()
            }
            LoginProvider.FACEBOOK -> {
                LoginManager.getInstance().logOut()
            }
        }
    }

    companion object {
        private const val TAG = "SocialLoginManager"
        const val RC_GOOGLE_SIGN_IN = 9001
    }
}

// SecretManager.kt
class SecretManager(private val context: Context) {

    fun getGoogleClientId(): String {
        return getSecret("GOOGLE_CLIENT_ID") ?: ""
    }

    fun getGoogleClientSecret(): String {
        return getSecret("GOOGLE_CLIENT_SECRET") ?: ""
    }

    fun getFacebookAppId(): String {
        return getSecret("FACEBOOK_APP_ID") ?: ""
    }

    fun getFacebookAppSecret(): String {
        return getSecret("FACEBOOK_APP_SECRET") ?: ""
    }

    private fun getSecret(key: String): String? {
        // Priority 1: Environment variables (for local development)
        System.getenv(key)?.let { return it }

        // Priority 2: BuildConfig (set via gradle.properties or CI/CD)
        try {
            val buildConfigClass = Class.forName("${context.packageName}.BuildConfig")
            val field = buildConfigClass.getDeclaredField(key)
            field.isAccessible = true
            (field.get(null) as? String)?.let { return it }
        } catch (e: Exception) {
            Log.d(TAG, "Secret $key not found in BuildConfig: ${e.message}")
        }

        // Priority 3: Shared Preferences (for runtime configuration)
        val prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        prefs.getString(key, null)?.let { return it }

        // Priority 4: Resources (strings.xml)
        try {
            val resourceId = context.resources.getIdentifier(
                key.lowercase(),
                "string",
                context.packageName
            )
            if (resourceId != 0) {
                return context.getString(resourceId)
            }
        } catch (e: Exception) {
            Log.d(TAG, "Secret $key not found in resources: ${e.message}")
        }

        Log.w(TAG, "Secret $key not found in any source")
        return null
    }

    fun setSecret(key: String, value: String) {
        val prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        prefs.edit().putString(key, value).apply()
    }

    companion object {
        private const val TAG = "SecretManager"
        private const val PREFS_NAME = "secure_secrets"
    }
}

