import android.content.Intent
import android.os.Bundle
import android.widget.Button
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class SocialLoginActivity : AppCompatActivity() {

    private lateinit var socialLoginManager: SocialLoginManager

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_social_login)

        socialLoginManager = SocialLoginManager(this)
        socialLoginManager.initializeGoogle()
        socialLoginManager.initializeFacebook()

        setupLoginButtons()
    }

    private fun setupLoginButtons() {
        findViewById<Button>(R.id.btnGoogleLogin)?.setOnClickListener {
            loginWithGoogle()
        }

        findViewById<Button>(R.id.btnFacebookLogin)?.setOnClickListener {
            loginWithFacebook()
        }
    }

    private fun loginWithGoogle() {
        socialLoginManager.loginWithGoogle(this, object : SocialLoginManager.SocialLoginCallback {
            override fun onLoginSuccess(
                provider: SocialLoginManager.LoginProvider,
                userId: String,
                accessToken: String,
                email: String?
            ) {
                Toast.makeText(
                    this@SocialLoginActivity,
                    "Google Login Success: $email",
                    Toast.LENGTH_LONG
                ).show()
                // Handle successful login
            }

            override fun onLoginFailure(provider: SocialLoginManager.LoginProvider, error: String) {
                Toast.makeText(
                    this@SocialLoginActivity,
                    "Google Login Failed: $error",
                    Toast.LENGTH_LONG
                ).show()
            }

            override fun onLoginCancelled(provider: SocialLoginManager.LoginProvider) {
                Toast.makeText(
                    this@SocialLoginActivity,
                    "Google Login Cancelled",
                    Toast.LENGTH_SHORT
                ).show()
            }
        })
    }

    private fun loginWithFacebook() {
        socialLoginManager.loginWithFacebook(this, object : SocialLoginManager.SocialLoginCallback {
            override fun onLoginSuccess(
                provider: SocialLoginManager.LoginProvider,
                userId: String,
                accessToken: String,
                email: String?
            ) {
                Toast.makeText(
                    this@SocialLoginActivity,
                    "Facebook Login Success: $userId",
                    Toast.LENGTH_LONG
                ).show()
                // Handle successful login
            }

            override fun onLoginFailure(provider: SocialLoginManager.LoginProvider, error: String) {
                Toast.makeText(
                    this@SocialLoginActivity,
                    "Facebook Login Failed: $error",
                    Toast.LENGTH_LONG
                ).show()
            }

            override fun onLoginCancelled(provider: SocialLoginManager.LoginProvider) {
                Toast.makeText(
                    this@SocialLoginActivity,
                    "Facebook Login Cancelled",
                    Toast.LENGTH_SHORT
                ).show()
            }
        })
    }

    override fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        super.onActivityResult(requestCode, resultCode, data)
        socialLoginManager.handleActivityResult(requestCode, resultCode, data)
    }
}